import React from "react";
import { Image } from "..";

const ActiveCashbackGif = ({
  width = "360",
  height = "216",
  onClick,
}: Image) => {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      xmlnsXlink="http://www.w3.org/1999/xlink"
      width={width}
      height={height}
      onClick={onClick}
    >
      <image
        preserveAspectRatio="xMidYMid slice"
        width={width}
        height={height}
        xlinkHref="data:image/gif;base64,"
      />
    </svg>
  );
};

export default ActiveCashbackGif;
